 1	import * as React from 'react';
 2	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 3	import { referenceForModel } from '@odf/shared/utils';
 4	import {
 5	  HealthState,
 6	  WatchK8sResource,
 7	  useK8sWatchResource,
 8	} from '@openshift-console/dynamic-plugin-sdk';
 9	import {
10	  HealthBody,
11	  HealthItem,
12	} from '@openshift-console/dynamic-plugin-sdk-internal';
13	import * as _ from 'lodash-es';
14	import {
15	  GalleryItem,
16	  Gallery,
17	  Card,
18	  CardHeader,
19	  CardBody,
20	  CardTitle,
21	} from '@patternfly/react-core';
22	import { StorageClientModel } from '../../../models';
23	import { StorageClient } from '../../../types';
24	import '../../../../style.scss';
25	
26	const clientResource: WatchK8sResource = {
27	  kind: referenceForModel(StorageClientModel),
28	  isList: true,
29	};
30	
31	const getStorageClientHealth = (
32	  storageClient: StorageClient,
33	  loaded: boolean,
34	  loadError: any
35	) => {
36	  if (loadError) {
37	    return { state: HealthState.NOT_AVAILABLE, message: '' };
38	  }
39	  if (!loaded) {
40	    return { state: HealthState.LOADING, message: '' };
41	  }
42	  if (_.isEmpty(storageClient)) {
43	    return { state: HealthState.NOT_AVAILABLE };
44	  }
45	
46	  const phase = storageClient.status.phase;
47	  switch (phase) {
48	    case 'Initializing':
49	    case 'Progressing':
50	    case 'Onboarding':
51	    case 'Offboarding':
52	      return { state: HealthState.PROGRESS, message: phase };
53	    case 'Connected':
54	      return { state: HealthState.OK, message: phase };
55	    case 'Failed':
56	      return { state: HealthState.ERROR, message: phase };
57	    default:
58	      return { state: HealthState.NOT_AVAILABLE, message: '' };
59	  }
60	};
61	
62	export const StatusCard: React.FC = () => {
63	  const { t } = useCustomTranslation();
64	  const [data, loaded, loadError] =
65	    useK8sWatchResource<StorageClient[]>(clientResource);
66	
67	  const cephHealth = getStorageClientHealth(data?.[0], loaded, loadError);
68	
69	  return (
70	    <Card className="odf-overview-card--gradient">
71	      <CardHeader>
72	        <CardTitle>{t('Status')}</CardTitle>
73	      </CardHeader>
74	      <CardBody>
75	        <HealthBody>
76	          <Gallery className="odf-overview-status__health" hasGutter>
77	            <GalleryItem>
78	              <HealthItem
79	                title={t('Storage Client')}
80	                state={cephHealth.state}
81	                details={cephHealth.message}
82	              />
83	            </GalleryItem>
84	          </Gallery>
85	        </HealthBody>
86	      </CardBody>
87	    </Card>
88	  );
89	};
90	
91	export default StatusCard;

